// friday13.cs — Friday the 13th in the proleptic Gregorian calendar
#:property PublishAot=false

// Find the earliest Friday the 13th starting from 0001-01-01
var earliest = DateOnly.MinValue; // 0001-01-01
for (var d = new DateOnly(1, 1, 13); d.Year <= 9999; d = d.AddMonths(1))
{
    if (d.DayOfWeek == DayOfWeek.Friday)
    {
        earliest = d;
        break;
    }
}
Console.WriteLine($"Earliest Friday the 13th: {earliest:yyyy-MM-dd} ({earliest.DayOfWeek})");

// Count Friday the 13ths in a full 400-year cycle (the Gregorian calendar repeats every 400 years)
int count = 0;
for (var d = new DateOnly(1, 1, 13); d.Year <= 400; d = d.AddMonths(1))
{
    if (d.DayOfWeek == DayOfWeek.Friday)
        count++;
}
Console.WriteLine($"Friday the 13ths in a 400-year cycle: {count}");
Console.WriteLine($"Average per year: {count / 400.0:F4}");

// Bonus: show distribution by month across the 400-year cycle
var byMonth = new int[12];
for (var d = new DateOnly(1, 1, 13); d.Year <= 400; d = d.AddMonths(1))
{
    if (d.DayOfWeek == DayOfWeek.Friday)
        byMonth[d.Month - 1]++;
}
Console.WriteLine("\nDistribution by month (400-year cycle):");
for (int m = 0; m < 12; m++)
    Console.WriteLine($"  {new DateOnly(2000, m + 1, 1):MMMM,-10} {byMonth[m]}");

